# Create a CA policy requiring MFA AND compliant device (AND operator)
$grantControls = @{
    Operator = 'AND'
    BuiltInControls = @('mfa', 'compliantDevice')
}

# OR operator: user satisfies policy if ANY control is met (MFA OR compliant device)
$grantControls = @{
    Operator = 'OR'
    BuiltInControls = @('mfa', 'compliantDevice')
}

# Block access (no grant satisfies this — denies immediately)
$grantControls = @{
    Operator = 'OR'
    BuiltInControls = @('block')
}

# Use authentication strength instead of mfa built-in
# Built-in strength IDs are fixed; phishing-resistant = 00000000-0000-0000-0000-000000000004
$grantControls = @{
    Operator = 'OR'
    AuthenticationStrength = @{
        Id = '00000000-0000-0000-0000-000000000004'  # Phishing-resistant MFA
    }
}

# Require app protection policy (compliantApplication) for Office 365 on mobile
# This allows BYOD without requiring device enrollment
$conditions = @{
    ClientAppTypes = @('mobileAppsAndDesktopClients')
    Platforms = @{
        IncludePlatforms = @('android', 'iOS')
    }
    Applications = @{
        IncludeApplications = @('Office365')
    }
}
$grantControls = @{
    Operator = 'OR'
    BuiltInControls = @('compliantApplication')
}

# Note: approvedApplication vs compliantApplication
# approvedApplication — verified publisher list (legacy; deprecated for new policies)
# compliantApplication — requires Intune App Protection Policy; does NOT require enrollment
# Microsoft recommends compliantApplication for all new mobile access policies

# Three-tier risk-based policy set — deploy as separate CA policies

# Tier 1: Sign-in risk HIGH → block
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: Sign-in Risk HIGH - Block'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{ IncludeApplications = @('all') }
        SignInRiskLevels = @('high')
    }
    GrantControls = @{
        Operator = 'OR'
        BuiltInControls = @('block')
    }
}

# Tier 2: Sign-in risk MEDIUM → require MFA
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: Sign-in Risk MEDIUM - MFA'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{ IncludeApplications = @('all') }
        SignInRiskLevels = @('medium')
    }
    GrantControls = @{
        Operator = 'OR'
        BuiltInControls = @('mfa')
    }
}

# Tier 3: User risk HIGH → require password change (SSPR) + MFA
New-MgIdentityConditionalAccessPolicy -BodyParameter @{
    DisplayName = 'CA: User Risk HIGH - Password Change'
    State = 'enabled'
    Conditions = @{
        Users = @{ IncludeUsers = @('all') }
        Applications = @{ IncludeApplications = @('all') }
        UserRiskLevels = @('high')
    }
    GrantControls = @{
        Operator = 'AND'
        BuiltInControls = @('mfa', 'passwordChange')
    }
}

# Terraform: CA policy with phishing-resistant MFA for admin roles
resource "azuread_conditional_access_policy" "admin_phishing_resistant" {
  display_name = "CA: Admins - Phishing-resistant MFA"
  state        = "enabled"

  conditions {
    users {
      included_roles = [
        "62e90394-69f5-4237-9190-012177145e10",  # Global Administrator
        "e8611ab8-c189-46e8-94e1-60213ab1f814",  # Privileged Role Administrator
        "194ae4cb-b126-40b2-bd5b-6091b380977d",  # Security Administrator
      ]
    }
    applications {
      included_applications = ["All"]
    }
    client_app_types = ["all"]
  }

  grant_controls {
    operator = "OR"
    authentication_strength_policy_id = "00000000-0000-0000-0000-000000000004"
    # 000...0004 = Phishing-resistant MFA (built-in strength)
  }
}

# Terraform: BYOD policy — MAM or compliant device
resource "azuread_conditional_access_policy" "byod_mam_or_managed" {
  display_name = "CA: BYOD - MAM or Managed Device"
  state        = "enabled"

  conditions {
    users { included_users = ["All"] }
    applications {
      included_applications = ["Office365"]
    }
    platforms {
      included_platforms = ["android", "iOS"]
    }
    client_app_types = ["mobileAppsAndDesktopClients"]
  }

  grant_controls {
    operator          = "OR"
    built_in_controls = ["compliantDevice", "compliantApplication"]
  }
}

# Graph API: read all CA policies and extract grant controls
$policies = Invoke-MgGraphRequest -Method GET \
    -Uri 'https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies' \
    -OutputType PSObject

foreach ($policy in $policies.value) {
    $grant = $policy.grantControls
    if ($null -eq $grant) {
        Write-Host "$($policy.displayName) — No grant controls (session-only policy)"
        continue
    }
    $controls = ($grant.builtInControls -join ', ')
    $strength = if ($grant.authenticationStrength) { $grant.authenticationStrength.displayName } else { 'N/A' }
    Write-Host "$($policy.displayName)"
    Write-Host "  Operator: $($grant.operator)"
    Write-Host "  Built-in: $controls"
    Write-Host "  Auth Strength: $strength"
    Write-Host "  State: $($policy.state)"
}

# Find all block policies and list their exclusions (safety audit)
foreach ($policy in $policies.value) {
    $grant = $policy.grantControls
    if ($grant -and $grant.builtInControls -contains 'block') {
        $excludedUsers = $policy.conditions.users.excludeUsers -join ', '
        $excludedGroups = $policy.conditions.users.excludeGroups -join ', '
        Write-Host "BLOCK POLICY: $($policy.displayName)"
        Write-Host "  Excluded users: $excludedUsers"
        Write-Host "  Excluded groups: $excludedGroups"
    }
}
